import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
// import MoveForward from "@components/common/move-forward";
import PocOpenSourceScreen from "@screens/poc-open-source";
import { useLocation } from "@reach/router";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";
import Layout_v2 from "@components/layout_v2";

const PocOpenSource = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "POC and Open Source Development Company", link: null },
  ];

  const { data } = props;
  const fileUrl =
    data?.pocDevImg?.childImageSharp?.gatsbyImageData?.images?.fallback?.src;
  const location = useLocation();
  const validData = data?.allMetaJson?.nodes[0];
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "We build Proof of Concept solutions to validate ideas, reduce risk, and help businesses move confidently from concept to full product development.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1604",
        },
      },
      {
        "@type": "FAQPage",

        mainEntity: [
          {
            "@type": "Question",
            name: "What is a POC company?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "A POC company builds Proof of Concept solutions to test ideas, validate feasibility, and reduce risk before full-scale product development.",
            },
          },
          {
            "@type": "Question",
            name: "What does POC stand for in production? ",
            acceptedAnswer: {
              "@type": "Answer",
              text: "POC stands for Proof of Concept, a small experiment used to verify that an idea or technology can work before full-scale production.",
            },
          },
          {
            "@type": "Question",
            name: "What is quality POC?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "A quality POC (Proof of Concept) is a well-built, clearly defined prototype that successfully proves an idea is feasible, meets key requirements, and delivers reliable results for decision-making.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <PocOpenSourceScreen db={db} />
      {/* <MoveForward db={db} /> */}
    </Layout_v2>
  );
};

export default PocOpenSource;

export const queryData = graphql`
  query MyQuery {
    pocDevImg: file(relativePath: { eq: "poc-development.png" }) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(filter: { slug: { eq: "poc-development-company" } }) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
